const inbox = $input.all();
const expectedRec = $('Get a message').first().json.toRecipients || [];
const convId = $('Update to processing').first().json.conversationId;
const sender = $('Update to processing').first().json.sender;
const agentEmail = $('Call \'Nudge Config\'').first().json.agentEmail;

// Flatten expected recipients into an array of addresses
const expectedAddresses = expectedRec.map(r => r.emailAddress?.address).filter(Boolean);

const reply = inbox.find(m =>
  m.json.conversationId === convId &&
  m.json.sender?.emailAddress?.address !== sender &&
  m.json.sender?.emailAddress?.address !== agentEmail && expectedAddresses.includes(m.json.sender?.emailAddress?.address)
);

return {
  hasReply: !!reply
};

let text = $('Update to processing').item.json.followUpMessage;

const html = text
  .replace(/\/n/g, '<br>')
  .replace(/\n/g, '<br>');

return {
  htmlMessage: html
};

return {
  messageId: $('If need followup based on time').item.json.messageId,
  status: "processing"
};

const openPeriods = $('Call \'Nudge Config\'').first().json.openPeriods;
const obj = $('Update to processing').item.json;

const sentDay = new Date();

const rawDelay = Number(obj.recommendedDelayInHours);

if(!(obj.shouldFollowUp) || $('Get new followUpCount and status').item.json.status == "followupmax") {
  return {
    nextFollowUpAt: "",
    finalDelayUsed: 0,
    usedFallback: false
  }
}

// Calculate delay
let delay;
if (isNaN(rawDelay) || rawDelay <= 0) {
  delay = getFallbackDelay($json.output);
} else {
  delay = Math.max(1, Math.min(rawDelay, 14));
}

// Compute initial follow-up time
let followUp = new Date(sentDay);
followUp.setTime(sentDay.getTime() + delay * 60 * 60 * 1000);

// --- NEW LOGIC: constrain to valid open periods (UTC-based) ---
const validSet = generateValidIntervalSet(openPeriods);
const followUpHour = followUp.getUTCHours();
const adjustedHour = getValidTime(validSet, followUpHour);

// Preserve minutes/seconds/milliseconds
const minutes = followUp.getUTCMinutes();
const seconds = followUp.getUTCSeconds();
const ms = followUp.getUTCMilliseconds();

if (adjustedHour !== followUpHour) {
  if (adjustedHour >= 24) {
    // rollover to next dayâ€™s min
    followUp.setUTCDate(followUp.getUTCDate() + 1);
    followUp.setUTCHours(adjustedHour - 24, minutes, seconds, ms);
  } else {
    followUp.setUTCHours(adjustedHour, minutes, seconds, ms);
  }
}

// Final output
return {
  nextFollowUpAt: followUp.toISOString(),
  finalDelayUsed: delay,
  usedFallback: delay !== rawDelay
};

// --- Helper functions ---
function getFallbackDelay(output) {
  if (output.urgency === "high") return 1;
  if (output.urgency === "medium") return 2;
  if (output.urgency === "low") return 4;
  return 3;
}

function generateValidIntervalSet(myvalidinterval) {
  const validintervalset = new Set();

  if (!Array.isArray(myvalidinterval)) return validintervalset;

  for (const interval of myvalidinterval) {
    if (!Array.isArray(interval) || interval.length !== 2) continue;

    const int0 = Number(interval[0]);
    const int1 = Number(interval[1]);

    if (Number.isNaN(int0) || Number.isNaN(int1)) continue;
    if (int0 < 0 || int0 > 23 || int1 < 0 || int1 > 23) continue;

    const mini = Math.min(int0, int1);
    const maxi = Math.max(int0, int1);

    for (let i = mini; i <= maxi; i++) {
      validintervalset.add(i);
    }
  }

  return validintervalset;
}

function getValidTime(myvalidintervalset, time) {
  try {
    myvalidintervalset = new Set(myvalidintervalset);

    if (myvalidintervalset.size === 0) return time;

    const arr = Array.from(myvalidintervalset).sort((a, b) => a - b);

    const min = arr[0];
    const max = arr[arr.length - 1];

    if (time <= min) return min;
    if (time > max) return min + 24; // next dayâ€™s min

    if (myvalidintervalset.has(time)) return time;

    for (let val of arr) {
      if (val >= time) return val;
    }

    return time;
  } catch (e) {
    return time;
  }
}

const toList = ($('Get a message').item.json.toRecipients).filter((val) => val.emailAddress.address != $('Call \'Nudge Config\'').first().json.agentEmail);

const ccClean = ($('Get a message').item.json.ccRecipients).filter((val) => val.emailAddress.address != $('Call \'Nudge Config\'').first().json.agentEmail);

const ccList = [$('Get a message').first().json.sender, ...ccClean];

const bccList = ($('Get a message').item.json.bccRecipients).filter((val) => val.emailAddress.address != $('Call \'Nudge Config\'').first().json.agentEmail);

return {toList: toList, ccList: ccList, bccList: bccList};

