const obj = $('Update to processing').item.json;
const maximum = $('Call \'Nudge Config\'').first().json.maxFollowUpCount;

const mymaximum = Number(maximum) || 0;

const newCount = (obj?.followUpCount ?? 0) + 1;

return {
  followUpCount: newCount,
  status: mymaximum > 0 && newCount >= mymaximum? "followupmax": "pending"
}
